beforeHooks.code:
this.timeout(60000);
fkHeaders = await CommonAPI.tokenCreation('Flipkart');
// sharedNegAppId is created with Flipkart headers (still active at this point)
sharedNegAppId = await freshFkApp(null);
console.log(`[OS-2255 SETUP] sharedNegAppId: ${sharedNegAppId}`);
// Paytm cross-partner headers — best-effort; REG-02 skips if token unavailable
try { ptHeaders = await CommonAPI.tokenCreation('Paytm'); } catch (e) { console.warn('[OS-2255] Paytm token unavailable:', e.message); }
// Restore Flipkart as the active module-level headers for subsequent app creations
fkHeaders = await CommonAPI.tokenCreation('Flipkart');

