tests.code:
const appId = await freshFkApp(this);
const payload = buildPayload();
addContext(this, { title: 'Basic Details Request', value: payload });
const res = await API.apiRequest(
    constants.baseURI2, 'post', constants.BasicDetails + appId, payload, fkHeaders
);
addContext(this, { title: 'Basic Details Response', value: res.body });
assert200Contract(res, appId);
const profile = await CommonAPI.getcustomerProfile(appId);
addContext(this, { title: 'Customer Profile Response', value: profile.body });
const contacts     = profile.body?.response?.CUSTOMER?.CONTACT ?? [];
const emailContact = contacts.find(c => c.TYPE === 'EMAIL' && c.PRIMARY === 'Yes');
const customer     = profile.body?.response?.CUSTOMER;
addContext(this, {
    title: 'Customer Profile Validation',
    value: {
        email_id:       emailContact?.VALUE === payload.email_id
                            ? `Available in profile ✓ — ${emailContact.VALUE}`
                            : `FAIL ✗ — expected: ${payload.email_id}, found: ${emailContact?.VALUE ?? 'NOT FOUND'}`,
        marital_status: customer?.MARITAL_STATUS === payload.marital_status
                            ? `Available in profile ✓ — ${customer.MARITAL_STATUS}`
                            : `FAIL ✗ — expected: ${payload.marital_status}, found: ${customer?.MARITAL_STATUS ?? 'NOT FOUND'}`,
    },
});

