tests.code:
const profile = await CommonAPI.getcustomerProfile(p01AppId);
addContext(this, { title: 'Customer Profile Response', value: profile.body });
expect(profile.status, 'customer profile HTTP').to.equal(200);
const sentEmail = JsonUtils.readJsonFromFile1('Basicdetails_Flipkart').email_id;
const contacts  = profile.body.response?.CUSTOMER?.CONTACT ?? [];
const emailContact = contacts.find(c => c.TYPE === 'EMAIL' && c.PRIMARY === 'Yes');
addContext(this, {
    title: 'DB-01 Validation — email in CONTACT',
    value: {
        expected_TYPE:    'EMAIL',
        expected_PRIMARY: 'Yes',
        expected_VALUE:   sentEmail,
        actual_entry:     emailContact ?? 'NOT FOUND',
        actual_VALUE:     emailContact?.VALUE ?? 'NOT FOUND',
        pass:             emailContact?.VALUE === sentEmail,
    }
});
expect(emailContact, 'EMAIL entry exists in CONTACT').to.exist;
expect(emailContact.VALUE, 'stored email matches sent email').to.equal(sentEmail);

const profile = await CommonAPI.getcustomerProfile(p02AppId);
addContext(this, { title: 'Customer Profile Response', value: profile.body });
expect(profile.status, 'customer profile HTTP').to.equal(200);
const contacts     = profile.body.response?.CUSTOMER?.CONTACT ?? [];
const emailContact = contacts.find(c => c.TYPE === 'EMAIL' && c.PRIMARY === 'Yes');
addContext(this, {
    title: 'DB-02 Validation — email absent from CONTACT',
    value: {
        expected: 'No TYPE=EMAIL entry in CONTACT (email_id was omitted)',
        actual:   emailContact ?? 'absent (correct)',
        pass:     emailContact === undefined,
    }
});
expect(emailContact, 'no EMAIL entry in CONTACT when email_id omitted').to.be.undefined;

const profile = await CommonAPI.getcustomerProfile(p03AppId);
addContext(this, { title: 'Customer Profile Response', value: profile.body });
expect(profile.status, 'customer profile HTTP').to.equal(200);
const customer        = profile.body.response?.CUSTOMER;
const keyPresent      = 'MARITAL_STATUS' in (customer ?? {});
const storedValue     = customer?.MARITAL_STATUS;
addContext(this, {
    title: 'DB-03 Validation — MARITAL_STATUS key absent',
    value: {
        expected_key_present: false,
        actual_key_present:   keyPresent,
        actual_value:         storedValue ?? 'undefined (key not written)',
        note:                 'Conditional spread — key must be absent entirely, not null',
        pass:                 !keyPresent,
    }
});
expect(keyPresent, 'MARITAL_STATUS key absent when marital omitted').to.be.false;

